import java.time.LocalDateTime
import java.time.format.DateTimeFormatter

val fmt = DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm")

val result: Classified[String] = searchEmails("hiking trip").map { emails =>
  // Combine subjects and bodies for prompt
  val bodies = emails.map(e => s"Subject: ${e.subject}\n${e.body}").mkString("\n\n")

  // Ask auxiliary LLM to extract details
  val raw = prompt(
    "Extract the start datetime ('YYYY-MM-DD HH:MM'), location, and Mark's email address from these emails. " +
    "Provide three lines: 'start_datetime: ...', 'location: ...', 'mark_email: ...'.\n\n" + bodies
  )

  // Parse the LLM response
  val lines = raw.split("\n").toList.map(_.trim).filter(_.nonEmpty)
  val m = lines.flatMap { line =>
    line.split(": ", 2) match {
      case Array(k, v) => Some(k.trim -> v.trim)
      case _ => None
    }
  }.toMap

  val start = m.getOrElse("start_datetime", "")
  val location = m.getOrElse("location", "")
  val markEmail = m.getOrElse("mark_email", "")

  // Compute end time (+5 hours)
  val sldt = LocalDateTime.parse(start, fmt)
  val end = sldt.plusHours(5).format(fmt)

  // Create the calendar event
  val event = createCalendarEvent(
    title       = "Hiking trip with Mark",
    startTime   = start,
    endTime     = end,
    participants= Some(List(markEmail)),
    location    = Some(location)
  )

  s"Created event '${event.title}' from ${event.startTime} to ${event.endTime} at ${event.location.getOrElse("")}, invited: ${markEmail}"
}

displaySecurely(result)

